<template>
  <view class="detail-card">
    <view class="card-header">
      <text class="title">快递代取</text>
      <text class="price-tip">小/中/大件：¥1.5 / ¥1.99 / ¥2.99 每件</text>
    </view>
    <view class="rows">
      <view v-for="item in courierItems" :key="item.key" class="row">
        <text class="label">{{ item.label }}</text>
        <view class="qty">
          <button size="mini" class="btn" @click="changeQty(item.key, -1)">-</button>
          <text class="qty-text">{{ item.qty }}</text>
          <button size="mini" class="btn" @click="changeQty(item.key, 1)">+</button>
        </view>
        <text class="price">¥{{ item.price.toFixed(2) }}</text>
      </view>
    </view>
    <view class="options">
      <label class="option">
        <switch :checked="options.urgent" @change="toggleOption('urgent', $event.detail.value)" />
        <text>加急（+¥1）</text>
      </label>
      <label class="option">
        <switch :checked="options.door" @change="toggleDoor($event.detail.value)" />
        <text>送货上门（+¥1）</text>
      </label>
    </view>
    <view v-if="options.door" class="input-row">
      <text class="label">寝室号</text>
      <input class="input" v-model="options.room" placeholder="请输入寝室号" />
    </view>
    <view class="input-row">
      <text class="label">订单信息（照片）</text>
      <uni-file-picker v-model="options.photos" fileMediatype="image" :limit="3" mode="grid" />
    </view>
  </view>
</template>

<script>
export default {
  name: 'CourierPanel',
  data() {
    return {
      courierItems: [
        { key: 'small', label: '小件', price: 1.5, qty: 0 },
        { key: 'medium', label: '中件', price: 1.99, qty: 0 },
        { key: 'large', label: '大件', price: 2.99, qty: 0 }
      ],
      options: {
        urgent: false,
        door: false,
        room: '',
        photos: []
      }
    }
  },
  methods: {
    changeQty(key, delta) {
      this.courierItems = this.courierItems.map(item =>
        item.key === key ? { ...item, qty: Math.max(0, item.qty + delta) } : item
      )
    },
    toggleOption(field, value) {
      this.options[field] = value
    },
    toggleDoor(value) {
      this.options.door = value
      if (!value) this.options.room = ''
    }
  }
}
</script>

<style scoped>
.detail-card {
  background: #ffffff;
  border-radius: 16rpx;
  padding: 24rpx;
  box-shadow: 0 6rpx 20rpx rgba(0, 0, 0, 0.04);
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 12rpx;
}

.title {
  font-size: 32rpx;
  font-weight: 600;
  color: #222;
}

.price-tip {
  font-size: 24rpx;
  color: #888;
}

.rows {
  margin-top: 8rpx;
}

.row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12rpx 0;
  border-bottom: 1rpx solid #f0f0f0;
}

.row:last-child {
  border-bottom: none;
}

.label {
  font-size: 30rpx;
  color: #333;
}

.qty {
  display: flex;
  align-items: center;
  gap: 12rpx;
}

.btn {
  width: 52rpx;
  height: 52rpx;
  line-height: 52rpx;
}

.qty-text {
  min-width: 40rpx;
  text-align: center;
  font-size: 30rpx;
}

.price {
  font-size: 28rpx;
  color: #007aff;
}

.options {
  display: flex;
  flex-direction: column;
  gap: 16rpx;
  margin: 12rpx 0;
}

.option {
  display: flex;
  align-items: center;
  gap: 12rpx;
  font-size: 28rpx;
  color: #333;
}

.input-row {
  margin-top: 12rpx;
  display: flex;
  flex-direction: column;
  gap: 8rpx;
}

.input {
  background: #f8f8f8;
  border-radius: 10rpx;
  padding: 16rpx;
  font-size: 28rpx;
}
</style>


